// Código para n8n - Code Node
// Análise de Pedidos OR e PD - COM AGRUPAMENTO POR VENDEDOR

const content = $input.all().flatMap(item => item.json.content || []);

// Objeto para agrupar por vendedor
const porVendedor = {};

// Função para inicializar estrutura do vendedor
function getVendedor(codigo) {
  if (!porVendedor[codigo]) {
    porVendedor[codigo] = {
      OR_naoFaturados: [],
      OR_jaFaturados: [],
      PD_total: [],
      PD_jaFaturados: []
    };
  }
  return porVendedor[codigo];
}

// Arrays globais (totais da loja)
const OR_naoFaturados = [];
const OR_jaFaturados = [];
const PD_total = [];
const PD_jaFaturados = [];

for (const pedido of content) {
  const especie = pedido.especieDocumento;
  const jaFaturado = pedido.jaFaturado;
  const numero = pedido.numeroDocumento;
  const vendedor = pedido.codigoVendedor;
  const cliente = pedido.cliente?.nome || pedido.nomeConsumidorOuCliente || 'N/A';
  const valor = pedido.valorContabil || 0;
  const data = pedido.dataEntrada;

  const v = getVendedor(vendedor);

  if (especie === "OR") {
    if (jaFaturado === false) {
      const item = { numero, vendedor, cliente, valor, data };
      OR_naoFaturados.push(item);
      v.OR_naoFaturados.push(item);
    } else {
      let numeroPD = null;
      if (Array.isArray(pedido.itens) && pedido.itens.length > 0) {
        const itemComPD = pedido.itens.find(item => item.numeroFaturamento);
        numeroPD = itemComPD?.numeroFaturamento || null;
      }
      const item = { numeroOR: numero, numeroPD, vendedor, cliente, valor, data };
      OR_jaFaturados.push(item);
      v.OR_jaFaturados.push(item);
    }
  }

  if (especie === "PD") {
    const item = { numero, vendedor, cliente, valor, data, jaFaturado };
    PD_total.push(item);
    v.PD_total.push(item);

    if (jaFaturado === true) {
      const itemFat = { numero, vendedor, cliente, valor, data };
      PD_jaFaturados.push(itemFat);
      v.PD_jaFaturados.push(itemFat);
    }
  }
}

// Função para calcular métricas de um conjunto de dados
function calcularMetricas(dados) {
  const PD_naoFaturados = dados.PD_total.filter(p => p.jaFaturado === false);

  // Oportunidade = tudo que está pendente (OR não fechados + PD não finalizados)
  const oportunidade_qtd = PD_naoFaturados.length + dados.OR_naoFaturados.length;
  const oportunidade_valor = PD_naoFaturados.reduce((s, p) => s + p.valor, 0) + dados.OR_naoFaturados.reduce((s, p) => s + p.valor, 0);

  // Conversão = PD_faturados / (PD_total + OR_nao_faturados)
  // Universo de negociações = todos os PDs (que nasceram de OR ou direto) + ORs que ainda não viraram PD
  const universo_negociacoes = dados.PD_total.length + dados.OR_naoFaturados.length;
  const conversao = universo_negociacoes > 0 ? ((dados.PD_jaFaturados.length / universo_negociacoes) * 100).toFixed(1) : "0";

  return {
    orcamentos: {
      OR_total_qtd: dados.OR_naoFaturados.length + dados.OR_jaFaturados.length,
      OR_naoFaturados_qtd: dados.OR_naoFaturados.length,
      OR_naoFaturados_valor: dados.OR_naoFaturados.reduce((s, p) => s + p.valor, 0).toFixed(2),
      OR_jaFaturados_qtd: dados.OR_jaFaturados.length,
      OR_jaFaturados_valor: dados.OR_jaFaturados.reduce((s, p) => s + p.valor, 0).toFixed(2),
    },
    pedidos: {
      PD_total_qtd: dados.PD_total.length,
      PD_total_valor: dados.PD_total.reduce((s, p) => s + p.valor, 0).toFixed(2),
      PD_jaFaturados_qtd: dados.PD_jaFaturados.length,
      PD_jaFaturados_valor: dados.PD_jaFaturados.reduce((s, p) => s + p.valor, 0).toFixed(2),
      PD_naoFaturados_qtd: PD_naoFaturados.length,
      PD_naoFaturados_valor: PD_naoFaturados.reduce((s, p) => s + p.valor, 0).toFixed(2),
    },
    oportunidade: {
      oportunidade_faturamento_qtd: oportunidade_qtd,
      oportunidade_faturamento_valor: oportunidade_valor.toFixed(2),
      conversao_real_percentual: conversao + "%",
    }
  };
}

// Calcular métricas globais
const totalGlobal = {
  OR_naoFaturados,
  OR_jaFaturados,
  PD_total,
  PD_jaFaturados
};
const metricasGlobais = calcularMetricas(totalGlobal);

// Calcular métricas por vendedor
const vendedores = {};
for (const [codigo, dados] of Object.entries(porVendedor)) {
  vendedores[codigo] = calcularMetricas(dados);
}

// Data atual (ou pegar do primeiro pedido)
const dataHoje = new Date().toISOString().split('T')[0];

// UUID da empresa (único para todas as lojas TMC Alberto)
const EMPRESA_ID = "SEU_UUID_EMPRESA";  // Substituir pelo UUID real após rodar o SQL

// Mapeamento: código da loja → UUID da loja no Supabase
// IMPORTANTE: Após rodar o SQL, preencher com os UUIDs gerados
const LOJAS = {
  "067": "UUID_PORTAL_MORUMBI",      // Portal do Morumbi
  "173": "UUID_JARDIM_GUEDALA",      // Jardim Guedala
  "132": "UUID_VILA_ANDRADE",        // Vila Andrade
  "191": "UUID_VILA_MASCOTE",        // Vila Mascote
  "131": "UUID_CHACARA_SANTO_ANTONIO" // Chácara Santo Antônio
};

// Pega o código da loja que veio na chamada da API (do node anterior)
// Ajuste conforme o nome do seu node HTTP Request
const codigoLoja = $('HTTP Request').first().json.codigoEmpresa
  || $input.first().json.codigoEmpresa
  || "000";

const CONFIG = {
  empresa_id: EMPRESA_ID,
  loja_id: LOJAS[codigoLoja] || "LOJA_NAO_ENCONTRADA",
  codigo_loja: codigoLoja
};

// Função para formatar registro para o Supabase
function formatarParaSupabase(codigoVendedor, metricas, isLoja = false) {
  return {
    empresa_id: CONFIG.empresa_id,
    loja_id: CONFIG.loja_id,
    codigo_vendedor: isLoja ? "LOJA_TOTAL" : codigoVendedor,
    data: dataHoje,
    tipo: isLoja ? "loja" : "vendedor",

    // Orçamentos
    or_total_qtd: metricas.orcamentos.OR_total_qtd,
    or_nao_faturados_qtd: metricas.orcamentos.OR_naoFaturados_qtd,
    or_nao_faturados_valor: parseFloat(metricas.orcamentos.OR_naoFaturados_valor),
    or_ja_faturados_qtd: metricas.orcamentos.OR_jaFaturados_qtd,
    or_ja_faturados_valor: parseFloat(metricas.orcamentos.OR_jaFaturados_valor),

    // Pedidos
    pd_total_qtd: metricas.pedidos.PD_total_qtd,
    pd_total_valor: parseFloat(metricas.pedidos.PD_total_valor),
    pd_ja_faturados_qtd: metricas.pedidos.PD_jaFaturados_qtd,
    pd_ja_faturados_valor: parseFloat(metricas.pedidos.PD_jaFaturados_valor),
    pd_nao_faturados_qtd: metricas.pedidos.PD_naoFaturados_qtd,
    pd_nao_faturados_valor: parseFloat(metricas.pedidos.PD_naoFaturados_valor),

    // Oportunidade
    oportunidade_qtd: metricas.oportunidade.oportunidade_faturamento_qtd,
    oportunidade_valor: parseFloat(metricas.oportunidade.oportunidade_faturamento_valor),
    conversao_real_percentual: parseFloat(metricas.oportunidade.conversao_real_percentual.replace('%', '')),
  };
}

// Criar array de registros para inserção em batch
const registros = [];

// 1. Adiciona o total da loja
registros.push(formatarParaSupabase("LOJA_TOTAL", metricasGlobais, true));

// 2. Adiciona cada vendedor
for (const [codigo, metricas] of Object.entries(vendedores)) {
  registros.push(formatarParaSupabase(codigo, metricas, false));
}

// Retorna múltiplos items - cada um será uma linha no Supabase
return registros.map(registro => ({ json: registro }));

return [
  { json: { codigo: "067", loja_id: "3ac40de2-a41c-40ba-89a1-e9f659466460" } },
  { json: { codigo: "173", loja_id: "75be9d1d-de8c-4ba8-8860-f0b1c1612ed4" } },
  { json: { codigo: "132", loja_id: "0699e4d8-b66d-4d26-88d7-4a1637953f8a" } },
  { json: { codigo: "191", loja_id: "25d8aa28-6da7-4af8-8325-a612624c78bb" } },
  { json: { codigo: "131", loja_id: "d20cb60a-29d4-4ad6-a6fd-2a92e86d0032" } }
];
